18: 
19: 	readonly _serviceBrand: undefined;
20: 
21: 	private static _lastId: number = 0;
22: 
23: 	private readonly _extHosts = new Map<string, WindowUtilityProcess>();
24: 	private _shutdown = false;
25: 
26: 	constructor(
27: 		@ILogService private readonly _logService: ILogService,
28: 		@ILifecycleMainService private readonly _lifecycleMainService: ILifecycleMainService,
29: 		@IWindowsMainService private readonly _windowsMainService: IWindowsMainService,
30: 		@ITelemetryService private readonly _telemetryService: ITelemetryService,
31: 	) {
32: 		super();
33: 
34: 		// On shutdown: gracefully await extension host shutdowns
35: 		this._register(this._lifecycleMainService.onWillShutdown(e => {
36: 			this._shutdown = true;
37: 			e.join('extHostStarter', this._waitForAllExit(6000));
38: 		}));
39: 	}
40: 
41: 	override dispose(): void {
42: 		// Intentionally not killing the extension host processes
43: 		super.dispose();
44: 	}
45: 
46: 	private _getExtHost(id: string): WindowUtilityProcess {
47: 		const extHostProcess = this._extHosts.get(id);
48: 		if (!extHostProcess) {
49: 			throw new Error(`Unknown extension host!`);
50: 		}
51: 		return extHostProcess;
52: 	}
53: 
54: 	onDynamicStdout(id: string): Event<string> {
55: 		return this._getExtHost(id).onStdout;
56: 	}
57: 
58: 	onDynamicStderr(id: string): Event<string> {
59: 		return this._getExtHost(id).onStderr;
60: 	}
61: 
62: 	onDynamicMessage(id: string): Event<any> {
63: 		return this._getExtHost(id).onMessage;
64: 	}
65: 
66: 	onDynamicExit(id: string): Event<{ code: number; signal: string }> {
67: 		return this._getExtHost(id).onExit;
68: 	}
69: 
70: 	async createExtensionHost(): Promise<{ id: string }> {
71: 		if (this._shutdown) {
72: 			throw canceled();
73: 		}
74: 		const id = String(++ExtensionHostStarter._lastId);
75: 		const extHost = new WindowUtilityProcess(this._logService, this._windowsMainService, this._telemetryService, this._lifecycleMainService);
76: 		this._extHosts.set(id, extHost);
77: 		const disposable = extHost.onExit(({ pid, code, signal }) => {
78: 			disposable.dispose();
79: 			this._logService.info(`Extension host with pid ${pid} exited with code: ${code}, signal: ${signal}.`);
80: 			setTimeout(() => {
81: 				extHost.dispose();
82: 				this._extHosts.delete(id);
83: 			});
84: 
85: 			// See https://github.com/microsoft/vscode/issues/194477
86: 			// We have observed that sometimes the process sends an exit
87: 			// event, but does not really exit and is stuck in an endless
88: 			// loop. In these cases we kill the process forcefully after
89: 			// a certain timeout.
90: 			setTimeout(() => {
91: 				try {
92: 					process.kill(pid, 0); // will throw if the process doesn't exist anymore.
93: 					this._logService.error(`Extension host with pid ${pid} still exists, forcefully killing it...`);
94: 					process.kill(pid);
95: 				} catch (er) {
96: 					// ignore, as the process is already gone
97: 				}
98: 			}, 1000);
99: 		});
100: 		return { id };
